/**
 * @looprun-bench/telecom — the τ²-bench telecom domain agent.
 *
 * ⚠️ INTENTIONALLY EMPTY. The real content — the AgentSpec, theme, lexicon, the synthetic world +
 * presets, the eval set, and CERT.md — is GENERATED by the looprun `agentspec` skill. It was removed
 * for a clean NATIVE regeneration (run the skill via the Skill tool in a fresh session). See
 * ../../docs/roadmap.md for the exact steps (install skill → A→G→E→N→T → certify), after which this
 * file is replaced by the generated `agents/telecom/index.ts` (spec + theme) and `world/`.
 *
 * The three symbols below are PLACEHOLDERS that define the contract the shim consumes and keep the
 * workspace typechecking; they THROW at runtime — nothing may run until the domain is regenerated.
 */
import type { AgentSpec, TrunkTheme, AgentWorld } from 'looprun';

const notGenerated = (what: string): never => {
  throw new Error(`@looprun-bench/telecom: ${what} not generated — run the agentspec skill (see docs/roadmap.md)`);
};

/** The generated telecom AgentSpec (replaced on regeneration). */
export const telecomSupportSpec: AgentSpec = new Proxy({} as AgentSpec, { get: () => notGenerated('telecomSupportSpec') });

/** The generated domain theme. */
export const THEME: TrunkTheme = new Proxy({} as TrunkTheme, { get: () => notGenerated('THEME') });

/** The world contract the shim's transcript-adapter satisfies (its accessors are generated by G2). */
export type TelecomWorld = AgentWorld & { [accessor: string]: unknown };
